class Solution:
    def solveQueries(self, nums, queries):
        n = len(nums)
        result = []
        for q in queries:
            v = nums[q]
            best = -1
            for j in range(n):
                if j == q or nums[j] != v:
                    continue
                d = min(abs(q - j), n - abs(q - j))
                if best == -1 or d < best:
                    best = d
            result.append(best)
        return result

