class Solution:
    def solveQueries(self, nums, queries):
        from collections import defaultdict
        n = len(nums)
        groups = defaultdict(list)
        for i, v in enumerate(nums):
            groups[v].append(i)
        ans_by_index = {}
        for v, positions in groups.items():
            m = len(positions)
            if m < 2:
                for p in positions:
                    ans_by_index[p] = -1
                continue
            for i in range(m):
                p = positions[i]
                prev = positions[(i - 1) % m]
                nxt = positions[(i + 1) % m]
                d1 = min(abs(p - prev), n - abs(p - prev))
                d2 = min(abs(p - nxt), n - abs(p - nxt))
                ans_by_index[p] = min(d1, d2)
        return [ans_by_index[q] for q in queries]

