var solveQueries = function(nums, queries) {
    const n = nums.length;
    const groups = new Map();
    for (let i = 0; i < n; i++) {
        const v = nums[i];
        if (!groups.has(v)) groups.set(v, []);
        groups.get(v).push(i);
    }
    const ansByIndex = new Array(n).fill(-1);
    for (const positions of groups.values()) {
        const m = positions.length;
        if (m < 2) continue;
        for (let i = 0; i < m; i++) {
            const p = positions[i];
            const prev = positions[(i - 1 + m) % m];
            const nxt = positions[(i + 1) % m];
            const d1 = Math.min(Math.abs(p - prev), n - Math.abs(p - prev));
            const d2 = Math.min(Math.abs(p - nxt), n - Math.abs(p - nxt));
            ansByIndex[p] = Math.min(d1, d2);
        }
    }
    return queries.map(q => ansByIndex[q]);
};
